const profile = $('Get User Profile').first().json;
const previousPlan = $('Get Previous Plan').first()?.json?.plan_json || null;

const weekNumber = getWeekNumber(new Date());
const year = new Date().getFullYear();

const restrictions = profile.dietary_restrictions ? (Array.isArray(profile.dietary_restrictions) ? profile.dietary_restrictions.join(', ') : profile.dietary_restrictions) : 'Ninguna';
const allergies = profile.food_allergies ? (Array.isArray(profile.food_allergies) ? profile.food_allergies.join(', ') : profile.food_allergies) : 'Ninguna';
const dislikes = profile.disliked_foods ? (Array.isArray(profile.disliked_foods) ? profile.disliked_foods.join(', ') : profile.disliked_foods) : 'Ninguno';

const prevSummary = previousPlan ? 'PLAN DE LA SEMANA ANTERIOR (evita repetir las mismas comidas):\n' + JSON.stringify(previousPlan).substring(0, 500) : '';

const prompt = 'Eres un nutriologo experto creando un plan de comidas personalizado.\n\nPERFIL DEL USUARIO:\n- Nombre: ' + profile.first_name + '\n- Objetivo calorico diario: ' + profile.caloric_target + ' kcal\n- Macros objetivo: ' + profile.protein_target_g + 'g proteina, ' + profile.carb_target_g + 'g carbohidratos, ' + profile.fat_target_g + 'g grasa\n- Restricciones dietarias: ' + restrictions + '\n- Alergias: ' + allergies + '\n- Alimentos que no le gustan: ' + dislikes + '\n- Cultura gastronomica: ' + (profile.local_culture || 'mexican') + '\n- Presupuesto para ingredientes: ' + (profile.budget_level || 'medium') + '\n- Numero de comidas al dia: ' + profile.meal_count + '\n- Semana numero: ' + weekNumber + '\n\n' + prevSummary + '\n\nINSTRUCCIONES:\n1. Genera un plan de comidas para 7 dias completos (lunes a domingo).\n2. Cada dia debe incluir ' + profile.meal_count + ' comidas distribuidas a lo largo del dia.\n3. Los macronutrientes de cada dia deben acercarse lo mas posible a los objetivos (+-5%).\n4. Las calorias diarias deben estar entre ' + (profile.caloric_target - 50) + ' y ' + (profile.caloric_target + 50) + '.\n5. NUNCA incluyas alimentos que el usuario no puede comer.\n6. Usa ingredientes accesibles y comunes en la cultura ' + (profile.local_culture || 'mexican') + '.\n7. Las preparaciones deben ser realistas: maximo 30 minutos de preparacion.\n8. Incluye variedad: no repitas la misma proteina mas de 2 veces por semana.\n\nFORMATO DE SALIDA: Responde EXCLUSIVAMENTE con JSON valido con la estructura: { "days": { "monday": { "meals": [...] }, ... }, "daily_totals": { "calories": N, "protein_g": N, "carb_g": N, "fat_g": N }, "shopping_list": [...] }. Cada meal debe tener: name, type (breakfast/lunch/dinner/snack), foods (array con name, quantity, unit, calories, protein_g, carb_g, fat_g), total_calories.';

return [{
  json: {
    prompt,
    userId: $('Execute Workflow Trigger').first().json.userId,
    weekNumber,
    year,
    profile
  }
}];

function getWeekNumber(d) {
  d = new Date(Date.UTC(d.getFullYear(), d.getMonth(), d.getDate()));
  d.setUTCDate(d.getUTCDate() + 4 - (d.getUTCDay() || 7));
  const yearStart = new Date(Date.UTC(d.getUTCFullYear(), 0, 1));
  return Math.ceil((((d - yearStart) / 86400000) + 1) / 7);
}

const responseContent = $('Generate Meal Plan').first().json.message?.content || $('Generate Meal Plan').first().json.choices?.[0]?.message?.content || '';
let plan;

try {
  plan = JSON.parse(responseContent);
} catch (e) {
  const jsonMatch = responseContent.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    plan = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('No se pudo parsear el plan de comidas generado por OpenAI');
  }
}

if (!plan.days || typeof plan.days !== 'object') {
  throw new Error('El plan no contiene la estructura de dias esperada');
}

const dayNames = ['monday', 'tuesday', 'wednesday', 'thursday', 'friday', 'saturday', 'sunday'];
for (const day of dayNames) {
  if (!plan.days[day] || !plan.days[day].meals) {
    throw new Error('El plan no contiene datos para ' + day);
  }
}

const totalCalories = dayNames.reduce((sum, day) => {
  const dayCalories = plan.days[day].meals.reduce((s, meal) => s + (meal.total_calories || 0), 0);
  return sum + dayCalories;
}, 0) / 7;

const prevData = $('Build Meal Plan Prompt').first().json;

return [{
  json: {
    plan,
    totalCalories: Math.round(totalCalories),
    userId: prevData.userId,
    weekNumber: prevData.weekNumber,
    year: prevData.year
  }
}];

const prevData = $('Parse and Validate Plan').first().json;
const plan = prevData.plan;
let formatted = 'Tu plan de comidas para esta semana (Semana ' + prevData.weekNumber + ', ' + prevData.year + '):\n\n';

const dayTranslations = {
  monday: 'Lunes', tuesday: 'Martes', wednesday: 'Miercoles',
  thursday: 'Jueves', friday: 'Viernes', saturday: 'Sabado', sunday: 'Domingo'
};

for (const [day, data] of Object.entries(plan.days)) {
  formatted += '*' + dayTranslations[day] + '*\n';
  let dayCalories = 0;
  let dayProtein = 0;
  for (const meal of data.meals) {
    const mealLabel = { breakfast: 'Desayuno', lunch: 'Comida', snack: 'Colacion', dinner: 'Cena' }[meal.type] || meal.type;
    formatted += '- ' + mealLabel + ': ' + meal.name + ' - ' + meal.total_calories + ' kcal\n';
    dayCalories += meal.total_calories || 0;
    dayProtein += meal.foods ? meal.foods.reduce((s, f) => s + (f.protein_g || 0), 0) : 0;
  }
  formatted += 'Total: ' + dayCalories + ' kcal | ~' + Math.round(dayProtein) + 'g proteina\n\n';
}

formatted += 'Quieres ver la receta de algun platillo? Solo dime cual.';

return [{ json: { formattedPlan: formatted, plan: prevData.plan, totalCalories: prevData.totalCalories } }];

return [{
  json: {
    formattedPlan: $json.formattedPlan,
    totalCalories: $json.totalCalories,
    success: true
  }
}];
